mapper.select:
select id, vehicle_no, brand, model, color, seat_count, daily_price, status, hot_flag, cover_image, description, created_at, updated_at from vehicle
and brand = #{brand}
and model like concat('%', #{model}, '%')
and status = #{status}
and seat_count = #{seatCount}
and (vehicle_no like concat('%', #{keyword}, '%') or brand like concat('%', #{keyword}, '%') or model like concat('%', #{keyword}, '%'))
order by id desc
